/// Only accessed from the run-loop thread (event tap callback), so no lock is needed.
nonisolated(unsafe) private var lastProcessedClickTime: UInt64 = 0

// MARK: - Event Tap Callback

private func eventTapCallback(
    proxy: CGEventTapProxy,
    type: CGEventType,
    event: CGEvent,
    refcon: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    // Watchdog: macOS disables the tap if the callback takes too long.
    // Re-enable it immediately to recover without requiring a relaunch.
    if type == .tapDisabledByTimeout || type == .tapDisabledByUserInput {
        if let refcon,
           let tap = refcon.assumingMemoryBound(to: CFMachPort?.self).pointee {
            CGEvent.tapEnable(tap: tap, enable: true)
            logger.warning("Event tap was disabled by macOS — re-enabled automatically.")
        }
        return Unmanaged.passUnretained(event)
    }

    // Determine if this event matches a configured trigger
    let flags = event.flags
    let isTrigger: Bool

    if type == .otherMouseDown && event.getIntegerValueField(.mouseEventButtonNumber) == 2 {
        // Middle click — check if enabled in preferences
        isTrigger = UserDefaults.standard.bool(forKey: "enableMiddleClick")
    } else if type == .leftMouseDown {
        // Left click — check configured modifier
        let modifierRaw = UserDefaults.standard.string(forKey: "leftClickModifier") ?? "option"
        if let modifier = TriggerModifier(rawValue: modifierRaw),
           let mask = modifier.eventFlagMask {
            isTrigger = flags.contains(mask)
        } else {
            isTrigger = false
        }
    } else {
        isTrigger = false
    }

    guard isTrigger else {
        return Unmanaged.passUnretained(event)
    }

    // Debounce: ignore clicks that arrive too soon after the last processed one
    let now = mach_absolute_time()
    let elapsedNano = machTimeToNanoseconds(now - lastProcessedClickTime)
    let elapsedSeconds = Double(elapsedNano) / 1_000_000_000

    if elapsedSeconds < debounceInterval {
        logger.debug("Click debounced (\(String(format: "%.0f", elapsedSeconds * 1000))ms since last).")
        return nil
    }

    // Run check synchronously to decide whether to swallow the event
    let isActive = MissionControlActiveChecker().isActive()

    if isActive {
        lastProcessedClickTime = now
        let location = event.location

        // Determine action from additional modifier keys
        let action: MouseAction
        if flags.contains(.maskCommand) {
            action = .closeAll
        } else if flags.contains(.maskShift) {
            action = .minimize
        } else {
            action = .close
        }

        Task { @MainActor in
            MissionControlManager.shared.handleMouseEvent(location: location, action: action)
        }

        // Return nil to completely intercept the event (blocks default action)
        return nil
    }

    // passUnretained: the caller owns the event, we must not retain it
    return Unmanaged.passUnretained(event)
}

/// Converts a `mach_absolute_time` delta to nanoseconds.
private func machTimeToNanoseconds(_ ticks: UInt64) -> UInt64 {
    var timebaseInfo = mach_timebase_info_data_t()
    mach_timebase_info(&timebaseInfo)
    return ticks * UInt64(timebaseInfo.numer) / UInt64(timebaseInfo.denom)
}

import Cocoa
import CoreGraphics
import ApplicationServices

@MainActor
class MissionControlManager {
    static let shared = MissionControlManager()

    func handleMouseEvent(location: CGPoint, isMiddle: Bool) {
        closeWindowAt(location: location)
    }

    private func closeWindowAt(location: CGPoint) {
        let systemWideElement = AXUIElementCreateSystemWide()
        var elementAtPosition: AXUIElement?

        let result = AXUIElementCopyElementAtPosition(systemWideElement, Float(location.x), Float(location.y), &elementAtPosition)

        if result == .success, let element = elementAtPosition {
            attemptToClose(element: element)
        }
    }

    private func attemptToClose(element: AXUIElement) {
        // 1. Try direct AXClose action or AXPress if it's a close button
        var actionNames: CFArray?
        if AXUIElementCopyActionNames(element, &actionNames) == .success, let actions = actionNames as? [String] {
            if actions.contains("AXClose") {
                AXUIElementPerformAction(element, "AXClose" as CFString)
                return
            } else if actions.contains("AXPress") {
                // Not perfectly safe if we just click any button, but if we are hovering a window, maybe not.
                // Let's check role first.
            }
        }

        // 2. See if we can find a close button attribute
        var closeButtonRef: CFTypeRef?
        if AXUIElementCopyAttributeValue(element, kAXCloseButtonAttribute as CFString, &closeButtonRef) == .success {
            let closeBtn = closeButtonRef as! AXUIElement
            AXUIElementPerformAction(closeBtn, kAXPressAction as CFString)
            return
        }

        // 3. Fallback: Identify app + title and close it in the background
        var pid: pid_t = 0
        if AXUIElementGetPid(element, &pid) == .success {
            var role: CFTypeRef?
            AXUIElementCopyAttributeValue(element, kAXRoleAttribute as CFString, &role)
            var subrole: CFTypeRef?
            AXUIElementCopyAttributeValue(element, kAXSubroleAttribute as CFString, &subrole)
            var title: CFTypeRef?
            AXUIElementCopyAttributeValue(element, kAXTitleAttribute as CFString, &title)

            let roleStr = role as? String ?? ""
            let subroleStr = subrole as? String ?? ""
            let titleStr = title as? String ?? ""

            print("Hovered Element - Role: \(roleStr), Subrole: \(subroleStr), Title: \(titleStr), PID: \(pid)")

            // Find window via PID and Title if it's not the docked app
            let appElement = AXUIElementCreateApplication(pid)
            if let targetWindow = findWindow(in: appElement, matchingTitle: titleStr) {
                print("Found match in app. Closing...")
                var targetCloseBtn: CFTypeRef?
                if AXUIElementCopyAttributeValue(targetWindow, kAXCloseButtonAttribute as CFString, &targetCloseBtn) == .success {
                    AXUIElementPerformAction(targetCloseBtn as! AXUIElement, kAXPressAction as CFString)
                } else {
                    // Fallback to cmd+w? Might need to bring to front first which breaks mission control.
                }
            } else {
                // If the element belongs to Dock (Mission Control proxies usually belong to com.apple.dock)
                // We'd have to find which app it belongs to.
                // Mission Control proxy text often contains "App Name - Window Title".
                print("Could not match window directly.")
            }
        }
    }

    private func findWindow(in appElement: AXUIElement, matchingTitle: String) -> AXUIElement? {
        guard !matchingTitle.isEmpty else { return nil }

        var windowsRef: CFTypeRef?
        if AXUIElementCopyAttributeValue(appElement, kAXWindowsAttribute as CFString, &windowsRef) == .success,
           let windows = windowsRef as? [AXUIElement] {

            for window in windows {
                var wTitle: CFTypeRef?
                if AXUIElementCopyAttributeValue(window, kAXTitleAttribute as CFString, &wTitle) == .success {
                    if let t = wTitle as? String, t == matchingTitle {
                        return window
                    }
                }
            }
        }
        return nil
    }
}

import Cocoa
import CoreGraphics
import ApplicationServices

@MainActor
class MissionControlManager {
    static let shared = MissionControlManager()

    func handleMouseEvent(location: CGPoint, isMiddle: Bool) {
        closeWindowAt(location: location)
    }

    private func closeWindowAt(location: CGPoint) {
        let systemWideElement = AXUIElementCreateSystemWide()
        var elementAtPosition: AXUIElement?

        let result = AXUIElementCopyElementAtPosition(systemWideElement, Float(location.x), Float(location.y), &elementAtPosition)

        if result == .success, let element = elementAtPosition {
            attemptToClose(element: element)
        }
    }

    private func attemptToClose(element: AXUIElement) {
        // 1. Try direct AXClose action or AXPress if it's a close button
        var actionNames: CFArray?
        if AXUIElementCopyActionNames(element, &actionNames) == .success, let actions = actionNames as? [String] {
            if actions.contains("AXClose") {
                AXUIElementPerformAction(element, "AXClose" as CFString)
                return
            } else if actions.contains("AXPress") {
                // Not perfectly safe if we just click any button, but if we are hovering a window, maybe not.
                // Let's check role first.
            }
        }

        // 2. See if we can find a close button attribute
        var closeButtonRef: CFTypeRef?
        if AXUIElementCopyAttributeValue(element, kAXCloseButtonAttribute as CFString, &closeButtonRef) == .success {
            let closeBtn = closeButtonRef as! AXUIElement
            AXUIElementPerformAction(closeBtn, kAXPressAction as CFString)
            return
        }

        // 3. Fallback: Identify app + title and close it in the background
        var pid: pid_t = 0
        if AXUIElementGetPid(element, &pid) == .success {
            var role: CFTypeRef?
            AXUIElementCopyAttributeValue(element, kAXRoleAttribute as CFString, &role)
            var subrole: CFTypeRef?
            AXUIElementCopyAttributeValue(element, kAXSubroleAttribute as CFString, &subrole)
            var title: CFTypeRef?
            AXUIElementCopyAttributeValue(element, kAXTitleAttribute as CFString, &title)

            let roleStr = role as? String ?? ""
            let subroleStr = subrole as? String ?? ""
            let titleStr = title as? String ?? ""

            print("Hovered Element - Role: \(roleStr), Subrole: \(subroleStr), Title: \(titleStr), PID: \(pid)")

            // Debug: print children and bounds to see what's actually here
            printElementInfo(element)
            if let parent = getParent(of: element) {
                print("Parent Info:")
                printElementInfo(parent)
            }

            // Find window via PID and Title if it's not the docked app
            let appElement = AXUIElementCreateApplication(pid)
            if let targetWindow = findWindow(in: appElement, matchingTitle: titleStr) {
                print("Found match in app. Closing...")
                var targetCloseBtn: CFTypeRef?
                if AXUIElementCopyAttributeValue(targetWindow, kAXCloseButtonAttribute as CFString, &targetCloseBtn) == .success {
                    AXUIElementPerformAction(targetCloseBtn as! AXUIElement, kAXPressAction as CFString)
                } else {
                    // Fallback to cmd+w? Might need to bring to front first which breaks mission control.
                }
            } else {
                // If the element belongs to Dock (Mission Control proxies usually belong to com.apple.dock)
                // We'd have to find which app it belongs to.
                // Mission Control proxy text often contains "App Name - Window Title".
                print("Could not match window directly.")
            }
        }
    }

    private func findWindow(in appElement: AXUIElement, matchingTitle: String) -> AXUIElement? {
        guard !matchingTitle.isEmpty else { return nil }

        var windowsRef: CFTypeRef?
        if AXUIElementCopyAttributeValue(appElement, kAXWindowsAttribute as CFString, &windowsRef) == .success,
           let windows = windowsRef as? [AXUIElement] {

            for window in windows {
                var wTitle: CFTypeRef?
                if AXUIElementCopyAttributeValue(window, kAXTitleAttribute as CFString, &wTitle) == .success {
                    if let t = wTitle as? String, t == matchingTitle {
                        return window
                    }
                }
            }
        }
        return nil
    }

    private func printElementInfo(_ element: AXUIElement) {
        var role: CFTypeRef?
        AXUIElementCopyAttributeValue(element, kAXRoleAttribute as CFString, &role)
        var boundsRef: CFTypeRef?
        var frame = CGRect.zero
        if AXUIElementCopyAttributeValue(element, kAXFrameAttribute as CFString, &boundsRef) == .success {
            AXValueGetValue(boundsRef as! AXValue, .cgRect, &frame)
        }
        var childrenRef: CFTypeRef?
        if AXUIElementCopyAttributeValue(element, kAXChildrenAttribute as CFString, &childrenRef) == .success, let children = childrenRef as? [AXUIElement] {
            print("Element Role: \(role ?? "nil" as CFTypeRef), Frame: \(frame), Children count: \(children.count)")
            for child in children {
                var childRole: CFTypeRef?
                AXUIElementCopyAttributeValue(child, kAXRoleAttribute as CFString, &childRole)
                var childTitle: CFTypeRef?
                AXUIElementCopyAttributeValue(child, kAXTitleAttribute as CFString, &childTitle)
                var childFrameRef: CFTypeRef?
                var childFrame = CGRect.zero
                if AXUIElementCopyAttributeValue(child, kAXFrameAttribute as CFString, &childFrameRef) == .success {
                    AXValueGetValue(childFrameRef as! AXValue, .cgRect, &childFrame)
                }
                print("  Child Role: \(childRole ?? "nil" as CFTypeRef), Title: \(childTitle ?? "nil" as CFTypeRef), Frame: \(childFrame)")
            }
        } else {
            print("Element Role: \(role ?? "nil" as CFTypeRef), Frame: \(frame), Children count: 0")
        }
    }

    private func getParent(of element: AXUIElement) -> AXUIElement? {
        var parentRef: CFTypeRef?
        if AXUIElementCopyAttributeValue(element, kAXParentAttribute as CFString, &parentRef) == .success {
            return (parentRef as! AXUIElement)
        }
        return nil
    }
}

