/// Minimum interval (in seconds) between processed clicks to prevent
/// racing close operations on rapid double-clicks.
private let debounceInterval: TimeInterval = MissionStrikeConfig.default.debounceInterval

/// Timestamp of the last click that was actually processed.
/// Only accessed from the run-loop thread (event tap callback), so no lock is needed.
nonisolated(unsafe) private var lastProcessedClickTime: UInt64 = 0

// MARK: - Event Tap Callback

private func eventTapCallback(
    proxy: CGEventTapProxy,
    type: CGEventType,
    event: CGEvent,
    refcon: UnsafeMutableRawPointer?
) -> Unmanaged<CGEvent>? {
    // Watchdog: macOS disables the tap if the callback takes too long.
    // Re-enable it immediately to recover without requiring a relaunch.
    if type == .tapDisabledByTimeout || type == .tapDisabledByUserInput {
        if let refcon,
           let tap = refcon.assumingMemoryBound(to: CFMachPort?.self).pointee {
            CGEvent.tapEnable(tap: tap, enable: true)
            logger.warning("Event tap was disabled by macOS — re-enabled automatically.")
        }
        return Unmanaged.passUnretained(event)
    }

    // Determine if this event matches a configured trigger
    let flags = event.flags
    let isTrigger: Bool

    if type == .otherMouseDown && event.getIntegerValueField(.mouseEventButtonNumber) == 2 {
        // Middle click — check if enabled in preferences
        isTrigger = UserDefaults.standard.bool(forKey: "enableMiddleClick")
    } else if type == .leftMouseDown {
        // Left click — check configured modifier
        let modifierRaw = UserDefaults.standard.string(forKey: "leftClickModifier") ?? "option"
        if let modifier = TriggerModifier(rawValue: modifierRaw),
           let mask = modifier.eventFlagMask {
            isTrigger = flags.contains(mask)
        } else {
            isTrigger = false
        }
    } else {
        isTrigger = false
    }

    guard isTrigger else {
        return Unmanaged.passUnretained(event)
    }

    // Debounce: ignore clicks that arrive too soon after the last processed one
    let now = mach_absolute_time()
    let elapsedNano = machTimeToNanoseconds(now - lastProcessedClickTime)
    let elapsedSeconds = Double(elapsedNano) / 1_000_000_000

    if elapsedSeconds < debounceInterval {
        logger.debug("Click debounced (\(String(format: "%.0f", elapsedSeconds * 1000))ms since last).")
        return nil
    }

    // Run check synchronously to decide whether to swallow the event
    let isActive = MissionControlActiveChecker().isActive()

    if isActive {
        lastProcessedClickTime = now
        let location = event.location

        // Determine action from additional modifier keys
        let action: MouseAction
        if flags.contains(.maskCommand) {
            action = .closeAll
        } else if flags.contains(.maskShift) {
            action = .minimize
        } else {
            action = .close
        }

        Task { @MainActor in
            MissionControlManager.shared.handleMouseEvent(location: location, action: action)
        }

        // Return nil to completely intercept the event (blocks default action)
        return nil
    }

    // passUnretained: the caller owns the event, we must not retain it
    return Unmanaged.passUnretained(event)
}

/// Converts a `mach_absolute_time` delta to nanoseconds.
private func machTimeToNanoseconds(_ ticks: UInt64) -> UInt64 {
    var timebaseInfo = mach_timebase_info_data_t()
    mach_timebase_info(&timebaseInfo)
    return ticks * UInt64(timebaseInfo.numer) / UInt64(timebaseInfo.denom)
}

import Foundation

/// Centralizes all tunable constants used across MissionStrike.
/// Adjust these values when macOS changes Mission Control behavior
/// in future versions (e.g., new Dock overlay layer numbers).
struct MissionStrikeConfig: Sendable {

    // MARK: - Mission Control Detection

    /// Dock overlay window layers observed during Mission Control (macOS 13–15).
    let missionControlOverlayLayers: Set<Int>

    /// Minimum fraction of a screen's dimensions a Dock overlay must cover
    /// to be considered a Mission Control overlay.
    let minimumScreenCoverageFraction: CGFloat

    /// Fallback screen size used when `NSScreen.screens` is empty (headless config).
    let fallbackScreenSize: CGSize

    // MARK: - Window Targeting

    /// Window owner names ignored during CGWindow fallback lookup.
    let ignoredWindowOwners: Set<String>

    // MARK: - Event Tap

    /// Minimum interval (seconds) between processed clicks to prevent
    /// racing close operations on rapid double-clicks.
    let debounceInterval: TimeInterval

    // MARK: - Default Configuration

    static let `default` = MissionStrikeConfig(
        missionControlOverlayLayers: [18, 20],
        minimumScreenCoverageFraction: 0.5,
        fallbackScreenSize: CGSize(width: 1920, height: 1080),
        ignoredWindowOwners: ["Dock", "Window Server", "Wallpaper"],
        debounceInterval: 0.3
    )
}

import SwiftUI
import ServiceManagement
import ApplicationServices
import os.log

private let logger = Logger(subsystem: "com.vibecoded.missionstrike", category: "Settings")

struct SettingsView: View {
    @AppStorage("showMenuBarIcon") private var showMenuBarIcon = true
    @AppStorage("enableSpaceClosing") private var enableSpaceClosing = true
    @State private var launchAtLogin = SMAppService.mainApp.status == .enabled
    @State private var isAccessibilityEnabled = AXIsProcessTrusted()

    /// Fires when any app's accessibility trust status changes in System Settings.
    private let accessibilityChanged = DistributedNotificationCenter.default()
        .publisher(for: Notification.Name("com.apple.accessibility.api"))

    var body: some View {
        VStack(alignment: .leading, spacing: 20) {
            HStack(spacing: 15) {
                if let nsImage = NSApplication.shared.applicationIconImage {
                    Image(nsImage: nsImage)
                        .resizable()
                        .scaledToFit()
                        .frame(width: 48, height: 48)
                }

                Text("MissionStrike Settings")
                    .font(.headline)
            }

            VStack(alignment: .leading, spacing: 5) {
                HStack {
                    Image(systemName: isAccessibilityEnabled ? "checkmark.circle.fill" : "exclamationmark.triangle.fill")
                        .foregroundStyle(isAccessibilityEnabled ? .green : .orange)
                    Text("Accessibility Permissions")
                }

                if !isAccessibilityEnabled {
                    Button("Open System Settings") {
                        let options: NSDictionary = ["AXTrustedCheckOptionPrompt": true]
                        _ = AXIsProcessTrustedWithOptions(options)
                    }
                    .font(.caption)
                }
            }

            Toggle("Show Menu Bar Icon", isOn: $showMenuBarIcon)

            Toggle("Enable Closing Spaces", isOn: $enableSpaceClosing)

            Toggle("Start at Login", isOn: $launchAtLogin)
                .onChange(of: launchAtLogin) {
                    toggleLaunchAtLogin()
                }

            Text("MissionStrike allows you to close windows in Mission Control using:\n• Middle Mouse Click\n• Option + Left Click")
                .font(.caption)
                .foregroundStyle(.secondary)

            Spacer()
        }
        .onAppear {
            refreshAccessibilityStatus()
        }
        .onReceive(accessibilityChanged) { _ in
            refreshAccessibilityStatus()
        }
        .padding()
        .frame(width: 320, height: 300)
    }

    private func refreshAccessibilityStatus() {
        let wasEnabled = isAccessibilityEnabled
        isAccessibilityEnabled = AXIsProcessTrusted()

        // When permissions are freshly granted, start the event tap immediately
        if !wasEnabled && isAccessibilityEnabled {
            EventTapManager.shared.start()
        }
    }

    private func toggleLaunchAtLogin() {
        do {
            if launchAtLogin {
                if SMAppService.mainApp.status != .enabled {
                    try SMAppService.mainApp.register()
                }
            } else {
                try SMAppService.mainApp.unregister()
            }
        } catch {
            logger.error("Failed to toggle launch at login: \(error.localizedDescription)")
            // Revert the toggle if it fails
            launchAtLogin = SMAppService.mainApp.status == .enabled
        }
    }
}

import SwiftUI
import ServiceManagement
import ApplicationServices
import os.log

private let logger = Logger(subsystem: "com.vibecoded.missionstrike", category: "Settings")

struct SettingsView: View {
    @AppStorage("showMenuBarIcon") private var showMenuBarIcon = true
    @AppStorage("enableSpaceClosing") private var enableSpaceClosing = true
    @AppStorage("enableMiddleClick") private var enableMiddleClick = true
    @AppStorage("leftClickModifier") private var leftClickModifier = "option"
    @State private var launchAtLogin = SMAppService.mainApp.status == .enabled
    @State private var isAccessibilityEnabled = AXIsProcessTrusted()

    /// Fires when any app's accessibility trust status changes in System Settings.
    private let accessibilityChanged = DistributedNotificationCenter.default()
        .publisher(for: Notification.Name("com.apple.accessibility.api"))

    var body: some View {
        VStack(alignment: .leading, spacing: 16) {
            HStack(spacing: 15) {
                if let nsImage = NSApplication.shared.applicationIconImage {
                    Image(nsImage: nsImage)
                        .resizable()
                        .scaledToFit()
                        .frame(width: 48, height: 48)
                }

                Text("MissionStrike Settings")
                    .font(.headline)
            }

            VStack(alignment: .leading, spacing: 5) {
                HStack {
                    Image(systemName: isAccessibilityEnabled
                          ? "checkmark.circle.fill"
                          : "exclamationmark.triangle.fill")
                        .foregroundStyle(isAccessibilityEnabled ? .green : .orange)
                    Text("Accessibility Permissions")
                }

                if !isAccessibilityEnabled {
                    Button("Open System Settings") {
                        let options: NSDictionary = ["AXTrustedCheckOptionPrompt": true]
                        _ = AXIsProcessTrustedWithOptions(options)
                    }
                    .font(.caption)
                }
            }

            // --- Trigger Bindings ---
            VStack(alignment: .leading, spacing: 8) {
                Text("Trigger Bindings")
                    .font(.subheadline)
                    .fontWeight(.medium)

                Toggle("Middle Mouse Click", isOn: $enableMiddleClick)

                HStack {
                    Text("Left Click Modifier:")
                    Picker("", selection: $leftClickModifier) {
                        ForEach(TriggerModifier.allCases, id: \.rawValue) { modifier in
                            Text(modifier.displayName).tag(modifier.rawValue)
                        }
                    }
                    .labelsHidden()
                    .frame(width: 130)
                }
            }

            // --- General ---
            Toggle("Show Menu Bar Icon", isOn: $showMenuBarIcon)

            Toggle("Enable Closing Spaces", isOn: $enableSpaceClosing)

            Toggle("Start at Login", isOn: $launchAtLogin)
                .onChange(of: launchAtLogin) {
                    toggleLaunchAtLogin()
                }

            Text("Actions in Mission Control:\n"
                 + "• Click → Close window\n"
                 + "• ⇧ Shift + Click → Minimize window\n"
                 + "• ⌘ Cmd + Click → Close all app windows")
                .font(.caption)
                .foregroundStyle(.secondary)

            Spacer()
        }
        .onAppear {
            refreshAccessibilityStatus()
        }
        .onReceive(accessibilityChanged) { _ in
            refreshAccessibilityStatus()
        }
        .padding()
        .frame(width: 340, height: 420)
    }

    private func refreshAccessibilityStatus() {
        let wasEnabled = isAccessibilityEnabled
        isAccessibilityEnabled = AXIsProcessTrusted()

        // When permissions are freshly granted, start the event tap immediately
        if !wasEnabled && isAccessibilityEnabled {
            EventTapManager.shared.start()
        }
    }

    private func toggleLaunchAtLogin() {
        do {
            if launchAtLogin {
                if SMAppService.mainApp.status != .enabled {
                    try SMAppService.mainApp.register()
                }
            } else {
                try SMAppService.mainApp.unregister()
            }
        } catch {
            logger.error("Failed to toggle launch at login: \(error.localizedDescription)")
            // Revert the toggle if it fails
            launchAtLogin = SMAppService.mainApp.status == .enabled
        }
    }
}

import Foundation
import Cocoa
import os.log

private let logger = Logger(
    subsystem: "com.vibecoded.missionstrike",
    category: "UpdateChecker"
)

/// Decoded payload from the GitHub Releases API.
private struct GitHubRelease: Decodable {
    let tagName: String
    let htmlURL: URL

    enum CodingKeys: String, CodingKey {
        case tagName = "tag_name"
        case htmlURL = "html_url"
    }
}

/// Checks for new releases by polling the GitHub Releases API.
/// No external dependencies — compares semantic version tags against
/// the running app version and presents an alert if an update is available.
@MainActor
final class UpdateChecker {
    static let shared = UpdateChecker()
    private init() {}

    private static let repoOwner = "SchoofsEbert"
    private static let repoName = "MissionStrike"
    private static let releasesURL = URL(
        string: "https://api.github.com/repos/\(repoOwner)/\(repoName)/releases/latest"
    )!

    /// UserDefaults key for the last automatic check timestamp.
    private static let lastCheckKey = "lastUpdateCheckTimestamp"

    /// Minimum interval between automatic checks (24 hours).
    private static let checkInterval: TimeInterval = 86_400

    /// The running app version (e.g. "1.2.0").
    private let currentVersion: String = {
        Bundle.main.object(
            forInfoDictionaryKey: "CFBundleShortVersionString"
        ) as? String ?? "1.2.0"
    }()

    // MARK: - Public API

    /// Performs an automatic background check, respecting the 24-hour cooldown.
    func checkIfNeeded() {
        let lastCheck = UserDefaults.standard.double(forKey: Self.lastCheckKey)
        let now = Date().timeIntervalSince1970
        guard now - lastCheck >= Self.checkInterval else {
            logger.debug("Skipping update check — last check was \(Int(now - lastCheck))s ago.")
            return
        }
        UserDefaults.standard.set(now, forKey: Self.lastCheckKey)
        check(userInitiated: false)
    }

    /// Performs an immediate check (e.g. from "Check for Updates…" menu item).
    func checkNow() {
        check(userInitiated: true)
    }

    // MARK: - Private

    private func check(userInitiated: Bool) {
        Task {
            do {
                let release = try await fetchLatestRelease()
                let latestVersion = release.tagName
                    .trimmingCharacters(in: .whitespaces)
                    .replacingOccurrences(of: "v", with: "")

                if isVersion(latestVersion, newerThan: currentVersion) {
                    logger.info("Update available: \(latestVersion) (current: \(self.currentVersion))")
                    showUpdateAlert(
                        latestVersion: latestVersion,
                        releaseURL: release.htmlURL
                    )
                } else if userInitiated {
                    showUpToDateAlert()
                } else {
                    logger.debug("Already on latest version (\(self.currentVersion)).")
                }
            } catch {
                logger.warning("Update check failed: \(error.localizedDescription)")
                if userInitiated {
                    showErrorAlert(error: error)
                }
            }
        }
    }

    // MARK: - GitHub API

    private func fetchLatestRelease() async throws -> GitHubRelease {
        var request = URLRequest(url: Self.releasesURL)
        request.setValue("application/vnd.github+json", forHTTPHeaderField: "Accept")
        request.timeoutInterval = 10

        let (data, response) = try await URLSession.shared.data(for: request)

        if let httpResponse = response as? HTTPURLResponse,
           !(200...299).contains(httpResponse.statusCode) {
            throw URLError(.badServerResponse)
        }

        return try JSONDecoder().decode(GitHubRelease.self, from: data)
    }

    // MARK: - Version Comparison

    /// Simple semantic version comparison (e.g. "1.3.0" > "1.2.0").
    private func isVersion(_ remote: String, newerThan local: String) -> Bool {
        let remoteParts = remote.split(separator: ".").compactMap { Int($0) }
        let localParts = local.split(separator: ".").compactMap { Int($0) }

        for index in 0..<max(remoteParts.count, localParts.count) {
            let remoteVal = index < remoteParts.count ? remoteParts[index] : 0
            let localVal = index < localParts.count ? localParts[index] : 0
            if remoteVal > localVal { return true }
            if remoteVal < localVal { return false }
        }
        return false
    }

    // MARK: - Alerts

    private func showUpdateAlert(latestVersion: String, releaseURL: URL) {
        let alert = NSAlert()
        alert.messageText = "Update Available"
        alert.informativeText = "MissionStrike \(latestVersion) is available "
            + "(you're on \(currentVersion)). "
            + "Would you like to open the download page?"
        alert.alertStyle = .informational
        alert.addButton(withTitle: "Download")
        alert.addButton(withTitle: "Later")

        if let icon = NSApplication.shared.applicationIconImage {
            alert.icon = icon
        }

        let response = alert.runModal()
        if response == .alertFirstButtonReturn {
            NSWorkspace.shared.open(releaseURL)
        }
    }

    private func showUpToDateAlert() {
        let alert = NSAlert()
        alert.messageText = "You're Up to Date"
        alert.informativeText = "MissionStrike \(currentVersion) is the latest version."
        alert.alertStyle = .informational
        alert.addButton(withTitle: "OK")

        if let icon = NSApplication.shared.applicationIconImage {
            alert.icon = icon
        }

        alert.runModal()
    }

    private func showErrorAlert(error: Error) {
        let alert = NSAlert()
        alert.messageText = "Update Check Failed"
        alert.informativeText = "Could not check for updates. "
            + "Please check your internet connection or try again later.\n\n"
            + "(\(error.localizedDescription))"
        alert.alertStyle = .warning
        alert.addButton(withTitle: "OK")
        alert.runModal()
    }
}

@testable import MissionStrike
import CoreGraphics
import Testing

// MARK: - Test Helpers

/// Builds a mock CGWindowList entry matching the shape returned by CGWindowListCopyWindowInfo.
private func mockWindowEntry(
    owner: String,
    layer: Int,
    bounds: CGRect
) -> [String: Any] {
    [
        kCGWindowOwnerName as String: owner,
        kCGWindowLayer as String: layer,
        kCGWindowBounds as String: [
            "X": bounds.origin.x,
            "Y": bounds.origin.y,
            "Width": bounds.width,
            "Height": bounds.height
        ]
    ]
}

private let standardScreen = CGSize(width: 1920, height: 1080)
private let smallScreen = CGSize(width: 1280, height: 800)

// MARK: - Detection Heuristic Tests

@Suite("Mission Control Detection")
struct MissionControlDetectionTests {

    // MARK: - Positive detection

    @Test("Dock overlay at layer 18 covering full screen is detected")
    func dockOverlayLayer18() {
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 18, bounds: CGRect(x: 0, y: 0, width: 1920, height: 1080))
        ]
        #expect(MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen]
        ))
    }

    @Test("Dock overlay at layer 20 covering full screen is detected")
    func dockOverlayLayer20() {
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 20, bounds: CGRect(x: 0, y: 0, width: 1920, height: 1080))
        ]
        #expect(MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen]
        ))
    }

    // MARK: - Negative detection

    @Test("Dock overlay that is too small for any screen is not detected")
    func dockOverlayTooSmall() {
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 18, bounds: CGRect(x: 0, y: 0, width: 200, height: 50))
        ]
        #expect(!MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen]
        ))
    }

    @Test("Non-Dock window at Mission Control layer is not detected")
    func nonDockOwnerIgnored() {
        let windowList = [
            mockWindowEntry(owner: "SomeOtherApp", layer: 18, bounds: CGRect(x: 0, y: 0, width: 1920, height: 1080))
        ]
        #expect(!MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen]
        ))
    }

    @Test("Dock window at non-Mission-Control layer is not detected")
    func dockWrongLayer() {
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 0, bounds: CGRect(x: 0, y: 0, width: 1920, height: 1080))
        ]
        #expect(!MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen]
        ))
    }

    @Test("Empty window list returns false")
    func emptyWindowList() {
        #expect(!MissionControlActiveChecker.isActive(
            windowList: [],
            screenSizes: [standardScreen]
        ))
    }

    // MARK: - Multi-display

    @Test("Overlay covering secondary screen but not primary is detected")
    func multiDisplaySecondaryScreenCovered() {
        // Overlay is 1280×800 — too small for the 1920×1080 primary,
        // but covers the 1280×800 secondary.
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 18, bounds: CGRect(x: 0, y: 0, width: 1280, height: 800))
        ]
        #expect(MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen, smallScreen]
        ))
    }

    @Test("Overlay too small for ALL screens is not detected on multi-display")
    func multiDisplayTooSmallForAll() {
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 18, bounds: CGRect(x: 0, y: 0, width: 400, height: 300))
        ]
        #expect(!MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen, smallScreen]
        ))
    }

    // MARK: - Fallback screen size

    @Test("Empty screen list uses fallback dimensions")
    func fallbackScreenSize() {
        // Overlay covers default fallback (1920×1080 × 0.5 = 960×540)
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 20, bounds: CGRect(x: 0, y: 0, width: 1920, height: 1080))
        ]
        #expect(MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: []
        ))
    }

    // MARK: - Custom config

    @Test("Custom overlay layers are respected")
    func customOverlayLayers() {
        let customConfig = MissionStrikeConfig(
            missionControlOverlayLayers: [99],
            minimumScreenCoverageFraction: 0.5,
            fallbackScreenSize: CGSize(width: 1920, height: 1080),
            ignoredWindowOwners: [],
            debounceInterval: 0.3
        )
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 99, bounds: CGRect(x: 0, y: 0, width: 1920, height: 1080))
        ]
        #expect(MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen],
            config: customConfig
        ))
        // Default layer 18 should NOT match with this config
        let defaultLayerList = [
            mockWindowEntry(owner: "Dock", layer: 18, bounds: CGRect(x: 0, y: 0, width: 1920, height: 1080))
        ]
        #expect(!MissionControlActiveChecker.isActive(
            windowList: defaultLayerList,
            screenSizes: [standardScreen],
            config: customConfig
        ))
    }

    @Test("Custom coverage fraction changes detection threshold")
    func customCoverageFraction() {
        let strictConfig = MissionStrikeConfig(
            missionControlOverlayLayers: [18, 20],
            minimumScreenCoverageFraction: 0.9,
            fallbackScreenSize: CGSize(width: 1920, height: 1080),
            ignoredWindowOwners: [],
            debounceInterval: 0.3
        )
        // 1600×900 covers 83% of 1920×1080 — passes 50% but fails 90%
        let windowList = [
            mockWindowEntry(owner: "Dock", layer: 18, bounds: CGRect(x: 0, y: 0, width: 1600, height: 900))
        ]
        #expect(MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen],
            config: .default
        ))
        #expect(!MissionControlActiveChecker.isActive(
            windowList: windowList,
            screenSizes: [standardScreen],
            config: strictConfig
        ))
    }
}

// MARK: - Config Tests

@Suite("MissionStrikeConfig")
struct MissionStrikeConfigTests {

    @Test("Default config contains expected overlay layers")
    func defaultOverlayLayers() {
        let config = MissionStrikeConfig.default
        #expect(config.missionControlOverlayLayers == [18, 20])
    }

    @Test("Default config contains Dock in ignored owners")
    func defaultIgnoredOwners() {
        let config = MissionStrikeConfig.default
        #expect(config.ignoredWindowOwners.contains("Dock"))
        #expect(config.ignoredWindowOwners.contains("Window Server"))
        #expect(!config.ignoredWindowOwners.contains("Finder"))
    }
}
